import { useEffect, useRef } from 'react';

// A 1-pixel silent blank MP4 video encoded in Base64 (from NoSleep.js)
const SILENT_MP4 = "data:video/mp4;base64,";

export const useWakeLock = () => {
  const wakeLockRef = useRef<any>(null);
  const videoRef = useRef<HTMLVideoElement | null>(null);

  // 1. HTML5 Screen Wake Lock API
  const requestWakeLock = async () => {
    if (!('wakeLock' in navigator)) return;
    try {
      if (wakeLockRef.current) return;
      wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
      console.log('Screen Wake Lock API acquired successfully.');
      wakeLockRef.current.addEventListener('release', () => {
        wakeLockRef.current = null;
      });
    } catch (err) {
      console.warn('Screen Wake Lock API was blocked or failed:', err);
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release();
        wakeLockRef.current = null;
      } catch (err) {
        console.warn('Failed to release Screen Wake Lock API:', err);
      }
    }
  };

  // 2. Invisible 1px MP4 Video Player Bypass (iOS / Safari fallback)
  const setupVideoFallback = () => {
    if (videoRef.current) return;

    // Create a tiny, hidden video element
    const video = document.createElement('video');
    video.src = SILENT_MP4;
    video.setAttribute('playsinline', '');
    video.setAttribute('loop', '');
    video.setAttribute('muted', '');
    video.muted = true;
    
    // Hide the video element off-screen
    video.style.position = 'absolute';
    video.style.top = '0';
    video.style.left = '0';
    video.style.width = '1px';
    video.style.height = '1px';
    video.style.opacity = '0.01';
    video.style.pointerEvents = 'none';
    video.style.zIndex = '-9999';

    document.body.appendChild(video);
    videoRef.current = video;

    const playVideo = () => {
      if (videoRef.current) {
        videoRef.current.play().catch((err) => {
          console.warn('Failed to play fallback wake-lock video:', err);
        });
      }
    };

    // Play video upon first user interaction (required by iOS Safari audio/video autoplay policy)
    const handleInteraction = () => {
      playVideo();
      document.removeEventListener('click', handleInteraction);
      document.removeEventListener('touchstart', handleInteraction);
    };

    document.addEventListener('click', handleInteraction);
    document.addEventListener('touchstart', handleInteraction);

    return () => {
      document.removeEventListener('click', handleInteraction);
      document.removeEventListener('touchstart', handleInteraction);
    };
  };

  const playVideoIfVisible = () => {
    if (videoRef.current && document.visibilityState === 'visible') {
      videoRef.current.play().catch((err) => {
        console.warn('Failed to play fallback video on focus:', err);
      });
    }
  };

  const pauseVideo = () => {
    if (videoRef.current) {
      videoRef.current.pause();
    }
  };

  useEffect(() => {
    // Attempt standard API
    requestWakeLock();

    // Initialize the invisible video player fallback for iOS
    const cleanupInteraction = setupVideoFallback();

    // Handle visibility transitions
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        requestWakeLock();
        playVideoIfVisible();
      } else {
        pauseVideo();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      
      if (cleanupInteraction) cleanupInteraction();
      
      if (videoRef.current) {
        videoRef.current.pause();
        videoRef.current.remove();
        videoRef.current = null;
      }
      
      releaseWakeLock();
    };
  }, []);
};
